// In charges.tsp
enum ChargeType { ..., CreditPurchase: "credit_purchase" }

@friendlyName("BillingCreditPurchaseCharge")
@summary("Credit purchase charge")
model CreditPurchaseCharge {
  ...ChargeBase<ChargeType.CreditPurchase>;
  // type-specific fields here
  @visibility(Lifecycle.Read, Lifecycle.Create)
  amount: Shared.Numeric;
}

// Update the union in charges.tsp
union Charge {
  flat_fee: FlatFeeCharge,
  usage_based: UsageBasedCharge,
  credit_purchase: CreditPurchaseCharge,
}

// In operations.tsp — extend ListCreditGrantsParamsFilter
@friendlyName("ListCreditGrantsParamsFilter")
model ListCreditGrantsParamsFilter {
  status?: CreditGrantStatus;
  currency?: Shared.CurrencyCode;
  // New field:
  feature?: Shared.ResourceKey;
}
// No changes needed in grant.tsp or index.tsp.
// Run: make gen-api && make generate
